func solve(s string, order []int64, k int64) int64 {
	n := len(s)
	replaced := make([]bool, n)

	// Function to count the number of valid substrings
	countValidSubstrings := func(s string, replaced []bool) int64 {
		count := int64(0)
		for i := 0; i < n; i++ {
			for j := i; j < n; j++ {
				valid := false
				for k := i; k <= j; k++ {
					if replaced[k] {
						valid = true
						break
					}
				}
				if valid {
					count++
				}
			}
		}
		return count
	}

	// Binary search for the minimum time t
	left := 0
	right := n
	result := -1

	for left <= right {
		mid := (left + right) / 2
		replaced = make([]bool, n)
		for i := 0; i < mid; i++ {
			replaced[int(order[i])] = true
		}
		validCount := countValidSubstrings(s, replaced)
		if validCount >= k {
			result = int64(mid)
			right = mid - 1
		} else {
			left = mid + 1
		}
	}

	return result
}
